import {Colors, getColorByIndex, labelsWithValue} from '.'
import type {ChartData, ChartDataset, Point} from 'chart.js'

export const generateLineData = (data: ChartData<'line'>, isDarkMode: boolean) => {
    const documentStyle = getComputedStyle(document.documentElement);

    const datasets: ChartDataset<'line', { [x: string]: number | Point | null }>[] = []

  const originalLabels = data?.labels
  const originalDatasets = data.datasets
  // const chartType = 'line'

  !!originalDatasets &&
    originalDatasets.forEach((originalDataset, index) => {
      let title = originalDataset.label

      const datasetValues = originalDataset.data

      const dataset: {
        [x: string]: number | Point | null
      } = {}

      !!originalLabels &&
        originalLabels?.forEach((label, labelIndex) => {
          title = originalDataset.label
            if(label && typeof label == 'string'){
                // @ts-ignore
              dataset[label] = datasetValues[labelIndex]
            }

        })

      // const color = Colors.pickLevels(originalDatasets.length + 1, isDarkMode, chartType)

      datasets.push({
          type: 'line',
          label: title,
          borderColor: documentStyle.getPropertyValue(`--${getColorByIndex(index)}-500`) as string,
          borderWidth: 2,
          fill: false,
          tension: 0.4,
          data: dataset
      })
    })

  return { labels: [], datasets }
}

export const generateBarData = (data: ChartData<'bar'>, isDarkMode: boolean) => {
  const datasets: ChartDataset<'bar', { [x: string]: number | [number, number] | null }>[] = []

  const originalLabels = data.labels
  const originalDatasets = data.datasets
  const chartType = 'bar'

  !!originalDatasets &&
    originalDatasets.forEach(originalDataset => {
      let title = originalDataset.label

      const datasetValues = originalDataset.data

        const dataset: {
        [x: string]: number | [number, number] | null
      } = {}

      !!originalLabels &&
        originalLabels.forEach((label, labelIndex) => {
          title = originalDataset.label
            if(typeof label == 'string'){
                // @ts-ignore
              dataset[label] = datasetValues[labelIndex]
            }
        })

      const color = Colors.pickLevels(originalDatasets.length, isDarkMode, chartType)

      datasets.push({
        label: title,
        borderColor: color.reverse(),
        backgroundColor: color,
        data: dataset
      })
    })

  return { labels: [], datasets }
}
export const generatePieData = (data: ChartData<'pie'>, isDarkMode: boolean) => {
  const datasets: ChartDataset<'pie', any>[] = []

  const originalLabels = data.labels
  const originalDatasets = data.datasets
  const chartType = 'pie'

  !!originalDatasets &&
    originalDatasets.forEach((item, _itemIndex, itemsArray) => {
      const colors = Colors.pickLevels(itemsArray.length, isDarkMode, chartType)

      datasets.push({
        label: item.label,
        data: item.data,
        backgroundColor: colors,
        borderColor: 'white',
        hoverOffset: 7.5
      })
    })

  return {
    labels: originalLabels ? originalLabels : labelsWithValue(originalDatasets),
    datasets: datasets
  }
}

