export const generateDoughnutData = (data: ChartData<'doughnut'>, isDarkMode: boolean) => {
    const documentStyle = getComputedStyle(document.documentElement);

    const datasets: ChartDataset<'doughnut', any>[] = []

  const labels = data.labels
  const datum = data.datasets
  // const chartType = 'doughnut'

  datum.forEach((item, _itemIndex, itemsArray) => {
    let totalLength = 0

    for (const item of itemsArray) {
      totalLength += item.data.length
    }

    const arr = Array.from(Array(totalLength).keys())
    datasets.push({
      ...item,
      label: item.label,
      data: item.data,
      backgroundColor: arr.map(index=>documentStyle.getPropertyValue(`--${getColorByIndex(index)}-500`)),
        hoverBackgroundColor: arr.map((index)=>documentStyle.getPropertyValue(`--${getColorByIndex(index)}-400`)),
      hoverOffset: 7.5,
        // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-expect-error
      cutout: '80%'
    })
  })

  return {
    labels: labels ? labels : labelsWithValue(datum),
    datasets: datasets
  }
}

